<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">PATIENT ACCOUNTS</span><h1>Patient Management</h1></div></div><div class="admin-panel"><div class="table-wrap"><table><thead><tr><th>Patient</th><th>Contact</th><th>Registered</th><th>Appointments</th><th>Status</th><th>Action</th></tr></thead><tbody><?php foreach($patients as$p):?><tr><td><b><?=e($p['name'])?></b><small>ID #<?=$p['id']?></small></td><td><?=e($p['email'])?><small><?=e($p['phone'])?></small></td><td><?=date('d M Y',strtotime($p['created_at']))?></td><td><?=$p['appointment_count']?></td><td><span class="status-pill <?=$p['is_active']?'confirmed':'cancelled'?>"><?=$p['is_active']?'Active':'Suspended'?></span></td><td><form method="post" action="<?=url('admin/patient-toggle')?>"><?=csrf_field()?><input type="hidden" name="id" value="<?=$p['id']?>"><button class="btn small <?=$p['is_active']?'danger':'outline'?>"><?=$p['is_active']?'Suspend':'Activate'?></button></form></td></tr><?php endforeach;?></tbody></table></div></div></div></section>

